# Deobfuscated Code Analysis

## Step-by-step Deobfuscation

The code uses a common obfuscation pattern: a string array (`a0_0x48e3`) with base64-encoded strings, a decoder function (`a0_0xbc85`), and a shuffling IIFE that rearranges the string array until a checksum matches.

After resolving all the encoded strings and renaming variables, here's the clean version:

```javascript
// Constants
var TAU = 6.283;          // ≈ 2π
var PHI = 1.618;          // Golden ratio
var SQRT_HALF = 0.707;    // ≈ √(1/2)

// Configuration parameters
var config = {
    parameterA: 4000,       // Repulsion strength between nodes
    parameterB: 0.004,      // Default spring stiffness
    parameterC: 0.92,       // Velocity damping/friction
    constantD: 0.0003,      // Gravity toward center
    limitE: 40,             // Max number of particles
    rateF: 0.04,            // Particle drag rate
    valueG: 0.06            // Camera smoothing factor
};

// --- NODES (graph vertices) ---
var nodes = [
    { id: "hub",       label: "Hub",        r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: "alpha",     label: "Alpha",      r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: "beta",      label: "Beta",       r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: "gamma",     label: "Gamma",      r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: "delta",     label: "Delta",      r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: "epsilon",   label: "Epsilon",    r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// --- EDGES (springs between nodes) ---
var edges = [
    { a: "hub", b: "alpha",   rest: 160, k: 0.006 },
    { a: "hub", b: "beta",    rest: 160, k: 0.005 },
    { a: "hub", b: "gamma",   rest: 170, k: 0.004 },
    { a: "hub", b: "delta",   rest: 170, k: 0.004 },
    { a: "hub", b: "epsilon", rest: 180, k: 0.003 },
    { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
    { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
    { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state (smooth interpolation)
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle system
var particles = [];
var frameCount = 0;

// Find a node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// --- PHYSICS SIMULATION ---
function simulate() {
    // 1) Node-to-node REPULSION (Coulomb's law style)
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = config.parameterA / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2) Edge SPRING forces (Hooke's law)
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        if (!nodeA || !nodeB) continue;

        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || config.parameterB) * displacement;

        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // 3) Apply DAMPING, GRAVITY toward center (400, 300), and update positions
    for (var n = 0; n < nodes.length; n++) {
        nodes[n].vx += (400 - nodes[n].x) * config.constantD;  // gravity to center X
        nodes[n].vy += (300 - nodes[n].y) * config.constantD;  // gravity to center Y
        nodes[n].vx *= config.parameterC;  // damping
        nodes[n].vy *= config.parameterC;
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// --- PARTICLE SPAWNER ---
function spawnParticle() {
    if (particles.length >= config.limitE) return;

    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT_HALF
    });
}

// --- PARTICLE UPDATER ---
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.vx *= 1 - config.rateF * 0.125;   // drag
        p.vy *= 1 - config.rateF * 0.125;
        p.x += p.vx;
        p.y += p.vy;
        p.age++;
        if (p.age > p.maxAge) {
            particles.splice(i, 1);  // remove dead particle
        }
    }
}

// --- CAMERA SMOOTHER ---
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.valueG;
    camera.y += (cameraTarget.y - camera.y) * config.valueG;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.valueG;
}

// --- MAIN LOOP ---
function tick() {
    simulate();
    updateParticles();
    updateCamera();
    if (frameCount % 3 === 0) spawnParticle();  // spawn every 3rd frame
    frameCount++;
}

setInterval(tick, 16);  // ~60 FPS
```

## What It Does — Summary

This is a **force-directed graph layout simulation** with a particle effects system:

1. **Force-Directed Graph**: 6 nodes ("Hub", "Alpha", "Beta", "Gamma", "Delta", "Epsilon") connected by 8 spring edges. Nodes repel each other (Coulomb repulsion) and are pulled together by springs (Hooke's law), with gentle gravity pulling everything toward center `(400, 300)` and velocity damping for stability.

2. **Particle System**: Every 3 frames, a decorative particle spawns from a random node and drifts outward with drag, dying after 800–2000 frames (cosmetic sparkle/ambient effect).

3. **Smooth Camera**: A camera position smoothly interpolates toward a target (for potential panning/zooming).

4. **Runs at ~60 FPS** via `setInterval(..., 16)`.

This is purely the **simulation/logic layer** — there's no rendering code here, so presumably a separate module reads the node/particle positions and draws them to a canvas.
